import React, { useCallback, useEffect, useState } from 'react';
import 'bootstrap/dist/css/bootstrap.min.css';
import AdminLogin from './components/auth/AdminLogin';
import DashboardTabs from './components/dashboard/DashboardTabs';
import ParcelsTable from './components/list/ParcelsTable';
import RegisterParcel from './components/register/RegisterParcel';
import TrackParcel from './components/track/TrackParcel';
import Header from './components/layout/Header';
import { AuthProvider, useAuth } from './context/AuthContext';
import {
  fetchParcels,
  loginAdmin,
  mapServerParcel,
  registerParcel,
  trackParcel as trackParcelApi,
  updateParcelStatus,
} from './services/api';

export default function App() {
  return (
    <AuthProvider>
      <AppShell />
    </AuthProvider>
  );
}

function AppShell() {
  const { isAuthenticated, admin, login, logout } = useAuth();
  const [activeTab, setActiveTab] = useState('track');
  const [parcels, setParcels] = useState([]);
  const [isLoadingParcels, setIsLoadingParcels] = useState(false);
  const [authLoading, setAuthLoading] = useState(false);
  const [registerLoading, setRegisterLoading] = useState(false);
  const [statusLoading, setStatusLoading] = useState(false);
  const [trackState, setTrackState] = useState({ result: null, error: null, loading: false });

  const loadParcels = useCallback(async () => {
    if (!isAuthenticated) return;
    setIsLoadingParcels(true);
    try {
      const data = await fetchParcels();
      setParcels(data.map(mapServerParcel));
    } catch (error) {
      console.error('Failed to fetch parcels', error);
    } finally {
      setIsLoadingParcels(false);
    }
  }, [isAuthenticated]);

  useEffect(() => {
    if (isAuthenticated && activeTab !== 'track') {
      loadParcels();
    }
  }, [isAuthenticated, activeTab, loadParcels]);

  const handleLogin = async (credentials) => {
    setAuthLoading(true);
    try {
      const data = await loginAdmin(credentials);
      login(data.token, data.admin);
    } catch (error) {
      alert(error.response?.data?.message || 'Invalid credentials');
    } finally {
      setAuthLoading(false);
    }
  };

  const handleTrackParcel = async (trackingId) => {
    setTrackState({ result: null, error: null, loading: true });
    try {
      const data = await trackParcelApi(trackingId);
      setTrackState({ result: mapServerParcel(data.parcel), error: null, loading: false });
    } catch (error) {
      const message = error.response?.data?.message || 'Parcel not found';
      setTrackState({ result: null, error: message, loading: false });
    }
  };

  const handleRegisterParcel = async (formData, resetForm) => {
    setRegisterLoading(true);
    try {
      const data = await registerParcel(formData);
      alert(`Parcel registered! Tracking ID: ${data.parcel.trackingId}`);
      resetForm();
      if (activeTab === 'list') {
        loadParcels();
      }
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to register parcel');
    } finally {
      setRegisterLoading(false);
    }
  };

  const handleStatusChange = async (parcelId, status) => {
    setStatusLoading(true);
    try {
      const { parcel } = await updateParcelStatus(parcelId, status);
      setParcels((prev) => prev.map((item) => (item.id === parcel._id ? mapServerParcel(parcel) : item)));
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to update status');
    } finally {
      setStatusLoading(false);
    }
  };

  const showDashboard = isAuthenticated;

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #e3f2fd 0%, #c5cae9 100%)' }}>
      <Header admin={showDashboard ? admin : null} onLogout={logout} />
      <main className="container py-4">
        {!showDashboard ? (
          <div className="row g-4">
            <div className="col-lg-7">
              <TrackParcel
                onTrack={handleTrackParcel}
                result={trackState.result}
                error={trackState.error}
                isLoading={trackState.loading}
              />
            </div>
            <div className="col-lg-5">
              <AdminLogin onSubmit={handleLogin} isLoading={authLoading} />
            </div>
          </div>
        ) : (
          <>
            <DashboardTabs activeTab={activeTab} onChange={setActiveTab} />
            <section className="mt-4">
              {activeTab === 'track' && (
                <TrackParcel
                  onTrack={handleTrackParcel}
                  result={trackState.result}
                  error={trackState.error}
                  isLoading={trackState.loading}
                />
              )}
              {activeTab === 'register' && (
                <RegisterParcel onSubmit={handleRegisterParcel} isLoading={registerLoading} />
              )}
              {activeTab === 'list' && (
                <>
                  {isLoadingParcels && <p className="text-muted">Loading parcels...</p>}
                  <ParcelsTable parcels={parcels} onStatusChange={handleStatusChange} isUpdating={statusLoading} />
                </>
              )}
            </section>
          </>
        )}
      </main>
    </div>
  );
}
